INSERT INTO events (event_id, title, description, type, date, end_date, location, created_by, status) VALUES
  ('e0000001-0000-0000-0000-000000000001', 'TechHack Baku 2025', 'Join 500+ developers, designers, and entrepreneurs for 48 hours of building. $15,000 prize pool. Mentors from Google, Microsoft, and regional startups.', 'hackathon',   '2026-09-15 09:00:00+04', '2026-09-17 18:00:00+04', 'Baku, Azerbaijan',   'a1b2c3d4-0001-0001-0001-000000000001', 'published'),
  ('e0000001-0000-0000-0000-000000000002', 'Caucasus AI Summit', '3 tracks, 28 speakers, 850 attendees. Topics: LLMs, computer vision, MLOps, and responsible AI. Sponsor expo and networking dinner included.', 'conference',  '2026-10-02 10:00:00+04', '2026-10-03 18:00:00+04', 'Tbilisi, Georgia',   'a1b2c3d4-0001-0001-0001-000000000002', 'published'),
  ('e0000001-0000-0000-0000-000000000003', 'Full-Stack React Bootcamp', 'Intensive 4-week program. 12 live modules, project-based learning, code reviews, and certificate of completion. Cohort size: 30.', 'bootcamp',    '2026-09-20 09:00:00+04', '2026-10-17 18:00:00+04', 'Online',              'a1b2c3d4-0001-0001-0001-000000000003', 'published'),
  ('e0000001-0000-0000-0000-000000000004', 'Startup Demo Day Summer 2026', '14 early-stage startups pitch live to investors. Audience voting for People''s Choice. Jury panel includes partners from regional VCs.', 'demo_day',    '2026-09-28 14:00:00+04', NULL,                     'Yerevan, Armenia',   'a1b2c3d4-0001-0001-0001-000000000004', 'published'),
  ('e0000001-0000-0000-0000-000000000005', 'Web Security Workshop', 'Learn OWASP Top 10, SQL injection, XSS, and CSRF in a controlled lab environment. Hands-on exercises. Certificate provided.', 'workshop',    '2026-10-05 09:00:00+04', '2026-10-05 18:00:00+04', 'Baku, Azerbaijan',   'a1b2c3d4-0001-0001-0001-000000000005', 'published'),
  ('e0000001-0000-0000-0000-000000000006', 'DevConnect Baku Meetup #18', 'Monthly developer gathering. Lightning talks, open networking, food and drinks. All experience levels welcome. Free entry.', 'meetup',      '2026-09-10 18:30:00+04', NULL,                     'Baku, Azerbaijan',   'a1b2c3d4-0001-0001-0001-000000000006', 'published'),
  ('e0000001-0000-0000-0000-000000000007', 'Tech Founders Networking Evening', 'Speed networking for founders, investors, and builders. Structured rounds followed by free networking. Profile matching enabled.', 'networking',  '2026-09-22 19:00:00+04', NULL,                     'Baku, Azerbaijan',   'a1b2c3d4-0001-0001-0001-000000000007', 'published'),
  ('e0000001-0000-0000-0000-000000000008', 'Regional Coding Competition 2026', 'Solo and team tracks. 5 algorithmic rounds, live leaderboard, and jury scoring. Top 3 teams win cash prizes.', 'competition', '2026-10-10 10:00:00+04', NULL,                     'Online',              'a1b2c3d4-0001-0001-0001-000000000001', 'published'),
  ('e0000001-0000-0000-0000-000000000009', 'Product Management Seminar', 'Full-day seminar with 4 senior PMs from Bolt, Pasha Bank, and Glovo. Frameworks, case studies, and open Q&A.', 'seminar',     '2026-10-15 10:00:00+04', '2026-10-15 18:00:00+04', 'Tbilisi, Georgia',   'a1b2c3d4-0001-0001-0001-000000000008', 'published')
